public class SecureWebViewActivity extends AppCompatActivity {
    private static final String TAG = "SecureWebView";
    private static final int PERMISSION_REQUEST_CAMERA = 1001;
    private static final int PERMISSION_REQUEST_LOCATION = 1002;
    private static final int REQUEST_IMAGE_CAPTURE = 2001;
    private static final int REQUEST_FILE_CHOOSER = 2002;
    
    private static final String ALLOWED_DOMAIN = "yourdomain.com";
    
    private WebView webView;
    private ValueCallback<Uri[]> filePathCallback;
    private String currentPhotoPath;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        
        webView = new WebView(this);
        setContentView(webView);
        
        configureSecureWebView();
        
        webView.addJavascriptInterface(new SecureJavaScriptBridge(this), "AndroidBridge");
        
        webView.loadUrl("https://" + ALLOWED_DOMAIN);
    }
    
    private void configureSecureWebView() {
        WebSettings webSettings = webView.getSettings();
        
        webSettings.setJavaScriptEnabled(true);
        
        webSettings.setAllowFileAccess(false);
        webSettings.setAllowContentAccess(false);
        webSettings.setAllowFileAccessFromFileURLs(false);
        webSettings.setAllowUniversalAccessFromFileURLs(false);
        
        webSettings.setDomStorageEnabled(true);
        webSettings.setDatabaseEnabled(true);
        
        webSettings.setMixedContentMode(WebSettings.MIXED_CONTENT_NEVER_ALLOW);
        
        webSettings.setSavePassword(false);
        webSettings.setSaveFormData(false);
        
        webSettings.setGeolocationEnabled(true);
        
        webSettings.setMediaPlaybackRequiresUserGesture(false);
        
        webSettings.setUserAgentString(webSettings.getUserAgentString() + " YourAppName/1.0");
        
        webView.setWebViewClient(new SecureWebViewClient());
        webView.setWebChromeClient(new SecureWebChromeClient());
        
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            webSettings.setSafeBrowsingEnabled(true);
        }
    }
    
    private class SecureWebViewClient extends WebViewClient {
        @Override
        public boolean shouldOverrideUrlLoading(WebView view, String url) {
            Uri uri = Uri.parse(url);
            String host = uri.getHost();
            
            if (host != null && host.endsWith(ALLOWED_DOMAIN)) {
                return false;
            }
            
            Intent intent = new Intent(Intent.ACTION_VIEW, uri);
            startActivity(intent);
            return true;
        }
        
        @Override
        public void onReceivedError(WebView view, int errorCode, String description, String failingUrl) {
            Toast.makeText(SecureWebViewActivity.this, "Error loading page", Toast.LENGTH_SHORT).show();
        }
    }
    
    private class SecureWebChromeClient extends WebChromeClient {
        @Override
        public void onGeolocationPermissionsShowPrompt(String origin, GeolocationPermissions.Callback callback) {
            if (origin.contains(ALLOWED_DOMAIN)) {
                callback.invoke(origin, true, false);
            } else {
                callback.invoke(origin, false, false);
            }
        }
        
        @Override
        public void onPermissionRequest(PermissionRequest request) {
            if (request.getOrigin().toString().contains(ALLOWED_DOMAIN)) {
                String[] requestedResources = request.getResources();
                for (String resource : requestedResources) {
                    if (resource.equals(PermissionRequest.RESOURCE_VIDEO_CAPTURE)) {
                        if (checkCameraPermission()) {
                            request.grant(new String[]{PermissionRequest.RESOURCE_VIDEO_CAPTURE});
                        } else {
                            requestCameraPermission();
                            request.deny();
                        }
                        return;
                    }
                }
            }
            request.deny();
        }
        
        @Override
        public boolean onShowFileChooser(WebView webView, ValueCallback<Uri[]> filePathCallback, 
                                        FileChooserParams fileChooserParams) {
            if (SecureWebViewActivity.this.filePathCallback != null) {
                SecureWebViewActivity.this.filePathCallback.onReceiveValue(null);
            }
            SecureWebViewActivity.this.filePathCallback = filePathCallback;
            
            Intent takePictureIntent = new Intent(MediaStore.ACTION_IMAGE_CAPTURE);
            if (takePictureIntent.resolveActivity(getPackageManager()) != null) {
                File photoFile = null;
                try {
                    photoFile = createImageFile();
                } catch (IOException ex) {
                    Log.e(TAG, "Error creating image file", ex);
                }
                
                if (photoFile != null) {
                    Uri photoURI = FileProvider.getUriForFile(SecureWebViewActivity.this,
                            getApplicationContext().getPackageName() + ".fileprovider",
                            photoFile);
                    takePictureIntent.putExtra(MediaStore.EXTRA_OUTPUT, photoURI);
                }
            }
            
            Intent contentSelectionIntent = new Intent(Intent.ACTION_GET_CONTENT);
            contentSelectionIntent.addCategory(Intent.CATEGORY_OPENABLE);
            contentSelectionIntent.setType("image/*");
            
            Intent[] intentArray;
            if (takePictureIntent != null) {
                intentArray = new Intent[]{takePictureIntent};
            } else {
                intentArray = new Intent[0];
            }
            
            Intent chooserIntent = new Intent(Intent.ACTION_CHOOSER);
            chooserIntent.putExtra(Intent.EXTRA_INTENT, contentSelectionIntent);
            chooserIntent.putExtra(Intent.EXTRA_TITLE, "Select Image");
            chooserIntent.putExtra(Intent.EXTRA_INITIAL_INTENTS, intentArray);
            
            startActivityForResult(chooserIntent, REQUEST_FILE_CHOOSER);
            return true;
        }
    }
    
    private File createImageFile() throws IOException {
        String timeStamp = new SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(new Date());
        String imageFileName = "JPEG_" + timeStamp + "_";
        File storageDir = getExternalFilesDir(null);
        File image = File.createTempFile(imageFileName, ".jpg", storageDir);
        currentPhotoPath = image.getAbsolutePath();
        return image;
    }
    
    public class SecureJavaScriptBridge {
        private Context context;
        
        public SecureJavaScriptBridge(Context context) {
            this.context = context;
        }
        
        @JavascriptInterface
        public void capturePhoto() {
            runOnUiThread(() -> {
                if (checkCameraPermission()) {
                    launchCamera();
                } else {
                    requestCameraPermission();
                }
            });
        }
        
        @JavascriptInterface
        public void getLocation() {
            runOnUiThread(() -> {
                if (checkLocationPermission()) {
                    fetchLocation();
                } else {
                    requestLocationPermission();
                }
            });
        }
        
        @JavascriptInterface
        public void initiatePayment(String amount, String currency, String orderId) {
            runOnUiThread(() -> {
                try {
                    double paymentAmount = Double.parseDouble(amount);
                    if (paymentAmount <= 0 || paymentAmount > 10000) {
                        notifyWebView("paymentError", "Invalid amount");
                        return;
                    }
                    
                    if (!currency.matches("^[A-Z]{3}$")) {
                        notifyWebView("paymentError", "Invalid currency");
                        return;
                    }
                    
                    if (!orderId.matches("^[a-zA-Z0-9_-]{1,50}$")) {
                        notifyWebView("paymentError", "Invalid order ID");
                        return;
                    }
                    
                    processPayment(paymentAmount, currency, orderId);
                } catch (NumberFormatException e) {
                    notifyWebView("paymentError", "Invalid amount format");
                }
            });
        }
        
        @JavascriptInterface
        public void showToast(String message) {
            runOnUiThread(() -> {
                String sanitizedMessage = message.replaceAll("[^a-zA-Z0-9 .,!?-]", "");
                if (sanitizedMessage.length() > 100) {
                    sanitizedMessage = sanitizedMessage.substring(0, 100);
                }
                Toast.makeText(context, sanitizedMessage, Toast.LENGTH_SHORT).show();
            });
        }
        
        @JavascriptInterface
        public String getAppVersion() {
            return "1.0.0";
        }
    }
    
    private boolean checkCameraPermission() {
        return ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) 
                == PackageManager.PERMISSION_GRANTED;
    }
    
    private void requestCameraPermission() {
        ActivityCompat.requestPermissions(this, 
                new String[]{Manifest.permission.CAMERA}, 
                PERMISSION_REQUEST_CAMERA);
    }
    
    private void launchCamera() {
        Intent takePictureIntent = new Intent(MediaStore.ACTION_IMAGE_CAPTURE);
        if (takePictureIntent.resolveActivity(getPackageManager()) != null) {
            File photoFile = null;
            try {
                photoFile = createImageFile();
            } catch (IOException ex) {
                Log.e(TAG, "Error creating image file", ex);
            }
            
            if (photoFile != null) {
                Uri photoURI = FileProvider.getUriForFile(this,
                        getApplicationContext().getPackageName() + ".fileprovider",
                        photoFile);
                takePictureIntent.putExtra(MediaStore.EXTRA_OUTPUT, photoURI);
                startActivityForResult(takePictureIntent, REQUEST_IMAGE_CAPTURE);
            }
        }
    }
    
    private boolean checkLocationPermission() {
        return ContextCompat.checkSelfPermission(this, Manifest.permission.ACCESS_FINE_LOCATION) 
                == PackageManager.PERMISSION_GRANTED;
    }
    
    private void requestLocationPermission() {
        ActivityCompat.requestPermissions(this, 
                new String[]{Manifest.permission.ACCESS_FINE_LOCATION}, 
                PERMISSION_REQUEST_LOCATION);
    }
    
    private void fetchLocation() {
        LocationManager locationManager = (LocationManager) getSystemService(Context.LOCATION_SERVICE);
        
        if (ActivityCompat.checkSelfPermission(this, Manifest.permission.ACCESS_FINE_LOCATION) 
                != PackageManager.PERMISSION_GRANTED) {
            return;
        }
        
        Location location = locationManager.getLastKnownLocation(LocationManager.GPS_PROVIDER);
        if (location == null) {
            location = locationManager.getLastKnownLocation(LocationManager.NETWORK_PROVIDER);
        }
        
        if (location != null) {
            try {
                JSONObject locationData = new JSONObject();
                locationData.put("latitude", location.getLatitude());
                locationData.put("longitude", location.getLongitude());
                locationData.put("accuracy", location.getAccuracy());
                
                notifyWebView("locationReceived", locationData.toString());
            } catch (Exception e) {
                Log.e(TAG, "Error creating location JSON", e);
                notifyWebView("locationError", "Failed to get location");
            }
        } else {
            notifyWebView("locationError", "Location not available");
        }
    }
    
    private void processPayment(double amount, String currency, String orderId) {
        try {
            JSONObject paymentData = new JSONObject();
            paymentData.put("amount", amount);
            paymentData.put("currency", currency);
            paymentData.put("orderId", orderId);
            paymentData.put("status", "success");
            paymentData.put("transactionId", "TXN" + System.currentTimeMillis());
            
            notifyWebView("paymentSuccess", paymentData.toString());
        } catch (Exception e) {
            Log.e(TAG, "Payment processing error", e);
            notifyWebView("paymentError", "Payment processing failed");
        }
    }
    
    private void notifyWebView(String event, String data) {
        String sanitizedData = data.replace("\\", "\\\\")
                                   .replace("'", "\\'")
                                   .replace("\n", "\\n")
                                   .replace("\r", "\\r");
        
        String javascript = String.format("javascript:if(window.onNativeEvent){window.onNativeEvent('%s','%s')}", 
                                         event, sanitizedData);
        
        runOnUiThread(() -> {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.KITKAT) {
                webView.evaluateJavascript(javascript, null);
            } else {
                webView.loadUrl(javascript);
            }
        });
    }
    
    @Override
    public void onRequestPermissionsResult(int requestCode, @NonNull String[] permissions, 
                                          @NonNull int[] grantResults) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults);
        
        if (requestCode == PERMISSION_REQUEST_CAMERA) {
            if (grantResults.length > 0 && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                launchCamera();
            } else {
                Toast.makeText(this, "Camera permission denied", Toast.LENGTH_SHORT).show();
                notifyWebView("cameraError", "Permission denied");
            }
        } else if (requestCode == PERMISSION_REQUEST_LOCATION) {
            if (grantResults.length > 0 && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                fetchLocation();
            } else {
                Toast.makeText(this, "Location permission denied", Toast.LENGTH_SHORT).show();
                notifyWebView("locationError", "Permission denied");
            }
        }
    }
    
    @Override
    protected void onActivityResult(int requestCode, int resultCode, Intent data) {
        super.onActivityResult(requestCode, resultCode, data);
        
        if (requestCode == REQUEST_IMAGE_CAPTURE) {
            if (resultCode == Activity.RESULT_OK) {
                if (currentPhotoPath != null) {
                    notifyWebView("photoCapture", currentPhotoPath);
                }
            } else {
                notifyWebView("cameraError", "Capture cancelled");
            }
        } else if (requestCode == REQUEST_FILE_CHOOSER) {
            if (filePathCallback == null) return;
            
            Uri[] results = null;
            if (resultCode == Activity.RESULT_OK) {
                if (data != null && data.getData() != null) {
                    results = new Uri[]{data.getData()};
                } else if (currentPhotoPath != null) {
                    results = new Uri[]{Uri.fromFile(new File(currentPhotoPath))};
                }
            }
            
            filePathCallback.onReceiveValue(results);
            filePathCallback = null;
        }
    }
    
    @Override
    public void onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack();
        } else {
            super.onBackPressed();
        }
    }
    
    @Override
    protected void onDestroy() {
        if (webView != null) {
            webView.removeJavascriptInterface("AndroidBridge");
            webView.destroy();
        }
        super.onDestroy();
    }
}